# Test fixtures for ast_pure_functions macro
#
# Each function below is annotated with its expected purity result.

# ============================================================================
# Pure functions — operate only on their arguments using primitive operations
# ============================================================================

def add(a, b):
    # PURE: only arithmetic on parameters
    return a + b

def square(n):
    # PURE: only arithmetic on a parameter
    return n * n

def greet(name):
    # PURE: only string concatenation on a parameter
    return "Hello, " + name

def max_of_two(a, b):
    # PURE: conditional on parameters, no external calls
    if a > b:
        return a
    return b

def factorial(n):
    # PURE: recursive — self-reference is treated as local
    if n <= 1:
        return 1
    return n * factorial(n - 1)

def contains(haystack, needle):
    # PURE: loop over parameter, no external calls
    for item in haystack:
        if item == needle:
            return True
    return False

def apply_twice(f, x):
    # PURE: calls f which is a parameter (local name)
    return f(f(x))

def sum_list(items):
    # PURE: uses a locally defined variable and a for loop over parameter
    total = 0
    for x in items:
        total = total + x
    return total

def clamp(value, lo, hi):
    # PURE: only comparisons and conditionals on parameters
    if value < lo:
        return lo
    if value > hi:
        return hi
    return value

# ============================================================================
# Impure functions — contain external calls, global state, or attribute access
# ============================================================================

def print_value(x):
    # IMPURE: calls external function 'print'
    print(x)

def get_input(prompt):
    # IMPURE: calls external function 'input'
    return input(prompt)

def read_file(path):
    # IMPURE: calls external function 'open'
    with open(path) as f:
        return f.read()

counter = 0

def increment_counter():
    # IMPURE: uses 'global' statement
    global counter
    counter += 1

def use_nonlocal():
    # IMPURE: uses 'nonlocal' (via a closure pattern)
    x = 0
    def inner():
        nonlocal x
        x += 1
    return inner

import os

def get_cwd():
    # IMPURE: calls os.getcwd() — 'os' is not a local name
    return os.getcwd()

import sys

def get_argv():
    # IMPURE: accesses sys.argv attribute — 'sys' is not a local name
    return sys.argv

def list_dir(path):
    # IMPURE: calls os.listdir() — 'os' is not a local name
    return os.listdir(path)

def write_output(data):
    # IMPURE: calls external 'print'
    print(str(data))

def call_external_by_name():
    # IMPURE: calls 'len' which is not locally defined
    return len([1, 2, 3])
